CREATE OR REPLACE VIEW vw_app_users WITH (security_invoker = ON) AS
SELECT
  t.app_user_id,
  t.name,
  t.email_address,
  t.role,
  t.is_active,
  calc_app_users_widgets(t.app_user_id) AS widgets,
  t.notes
FROM app_users t;

CREATE OR REPLACE VIEW vw_shapes WITH (security_invoker = ON) AS
SELECT
  t.shape_id,
  t.name,
  calc_shapes_sides(t.shape_id) AS sides,
  calc_shapes_how_many_sides(t.shape_id) AS how_many_sides,
  calc_shapes_is_rectangle(t.shape_id) AS is_rectangle,
  calc_shapes_is_triangle(t.shape_id) AS is_triangle,
  calc_shapes_is_right_triangle(t.shape_id) AS is_right_triangle,
  calc_shapes_sum_of_internal_angles(t.shape_id) AS sum_of_internal_angles,
  calc_shapes_max_angle(t.shape_id) AS max_angle,
  calc_shapes_hypotenuse_length_squared(t.shape_id) AS hypotenuse_length_squared,
  calc_shapes_non_hypotenuse_sides_squared(t.shape_id) AS non_hypotenuse_sides_squared,
  calc_shapes_pythagorean_theorem_holds(t.shape_id) AS pythagorean_theorem_holds
FROM shapes t;

CREATE OR REPLACE VIEW vw_sides WITH (security_invoker = ON) AS
SELECT
  t.side_id,
