  t.label,
  calc_sides_is_rectangle(t.side_id) AS is_rectangle,
  calc_sides_is_triangle(t.side_id) AS is_triangle,
  calc_sides_is_right_triangle(t.side_id) AS is_right_triangle,
  calc_sides_is_hypotenuse(t.side_id) AS is_hypotenuse,
  calc_sides_status_of_theorem(t.side_id) AS status_of_theorem,
  calc_sides_pythagorean_theorem_holds(t.side_id) AS pythagorean_theorem_holds,
  calc_sides_length_squared(t.side_id) AS length_squared,
  calc_sides_hypotenuse_length_squared(t.side_id) AS hypotenuse_length_squared,
  calc_sides_non_hypotenuse_length_squared(t.side_id) AS non_hypotenuse_length_squared,
  calc_sides_previous_side_length(t.side_id) AS previous_side_length,
  t.length,
  calc_sides_next_length(t.side_id) AS next_length,
  calc_sides_previous_angle(t.side_id) AS previous_angle,
  t.angle,
  calc_sides_next_angle(t.side_id) AS next_angle,
  t.previous_side,
