  t.shape,
  calc_sides_previous_label(t.side_id) AS previous_label,
  calc_sides_next_label(t.side_id) AS next_label
FROM sides t;

CREATE OR REPLACE VIEW vw_widgets WITH (security_invoker = ON) AS
SELECT
  t.widget_id,
  t.name,
  t.appuser,
  calc_widgets_name_from_appuser(t.widget_id) AS name_from_appuser,
  calc_widgets_email_address_from_appuser(t.widget_id) AS email_address_from_appuser,
  calc_widgets_role_from_appuser(t.widget_id) AS role_from_appuser,
  t.color
FROM widgets t;

